// TWISTED FLOATING POINT (tfp) - DETERMINISTIC REAL NUMBERS
// Twisted Floating Point provides IEEE-free floating-point arithmetic
// Built from TBB exponent + TBB mantissa, eliminating IEEE 754 problems
// CRITICAL: No -0, no NaN ambiguity, cross-platform bit-exact determinism

Get the next token from the input
pub func:tokenizer_next = Token(Tokenizer@:tok) {
    skip_whitespace(tok) ? NIL;

    // Save position for token
    int32:token_line = tok->line;
    int32:token_col = tok->column;

    int8:ch = peek(tok) ? 0i8;

    // End of file
    if (ch == 0i8) {
        Token:token = Token {
            type: TOK_EOF,
            line: token_line,
            column: token_col,
            str_value: NULL,
            num_value: 0.0
        };
        return token;
    }

    // Structural characters
    if (ch == 123i8) {  // '{'
        advance(tok) ? 0i8;
        Token:token = Token { type: TOK_LEFT_BRACE, line: token_line, column: token_col, str_value: NULL, num_value: 0.0 };
        return token;
    }
    if (ch == 125i8) {  // '}'
        advance(tok) ? 0i8;
        Token:token = Token { type: TOK_RIGHT_BRACE, line: token_line, column: token_col, str_value: NULL, num_value: 0.0 };
        return token;
    }
    if (ch == 91i8) {  // '['
        advance(tok) ? 0i8;
        Token:token = Token { type: TOK_LEFT_BRACKET, line: token_line, column: token_col, str_value: NULL, num_value: 0.0 };
        return token;
    }
    if (ch == 93i8) {  // ']'
        advance(tok) ? 0i8;
        Token:token = Token { type: TOK_RIGHT_BRACKET, line: token_line, column: token_col, str_value: NULL, num_value: 0.0 };
        return token;
    }
    if (ch == 44i8) {  // ','
        advance(tok) ? 0i8;
        Token:token = Token { type: TOK_COMMA, line: token_line, column: token_col, str_value: NULL, num_value: 0.0 };
        return token;
    }
    if (ch == 58i8) {  // ':'
        advance(tok) ? 0i8;
        Token:token = Token { type: TOK_COLON, line: token_line, column: token_col, str_value: NULL, num_value: 0.0 };
        return token;
    }

    // String literal
    if (ch == 34i8) {  // '"'
        int8->:str_val = parse_string(tok) ? NULL;
        Token:token = Token { type: TOK_STRING, line: token_line, column: token_col, str_value: str_val, num_value: 0.0 };
        return token;
    }

    // Number
    if (is_digit(ch) ? 0i8 || ch == 45i8) {  // Digit or '-'
        flt64:num_val = parse_number(tok) ? 0.0;
        Token:token = Token { type: TOK_NUMBER, line: token_line, column: token_col, str_value: NULL, num_value: num_val };
        return token;
    }

    // Keywords
    if (ch == 116i8) {  // 't' - possibly 'true'
        if (parse_keyword(tok, "true") ? 0i32) {
            Token:token = Token { type: TOK_TRUE, line: token_line, column: token_col, str_value: NULL, num_value: 0.0 };
            return token;
        } else {
            // Error
        }
    }
    if (ch == 102i8) {  // 'f' - possibly 'false'
        if (parse_keyword(tok, "false") ? 0i32) {
            Token:token = Token { type: TOK_FALSE, line: token_line, column: token_col, str_value: NULL, num_value: 0.0 };
            return token;
        } else {
            // Error
        }
    }
    if (ch == 110i8) {  // 'n' - possibly 'null'
        if (parse_keyword(tok, "null") ? 0i32) {
            Token:token = Token { type: TOK_NULL, line: token_line, column: token_col, str_value: NULL, num_value: 0.0 };
            return token;
        } else {
            // Error
        }
    }

    // Unknown character - error
    Token:error_token = Token { type: TOK_ERROR, line: token_line, column: token_col, str_value: NULL, num_value: 0.0 };
    return error_token;
};

