};
}
```

// Aria native - using NIL for optional values
func:findUser = obj?(string:username) {
    obj?:user = database.lookup(username);
    if (user == NIL) {
        pass(NIL);  // No user found, return NIL
    }
    pass(user);
};
obj?:res = findUser("bob") ?? NIL;

```aria
func:quicksort_i32_range = NIL(int32->:arr, int32:low, int32:high) {
if (low < high) {
        int32:pi = partition_i32(arr, low, high);
        quicksort_i32_range(arr, low, pi - 1) ? NIL;
