```

---

## Special Values

### NaN Operations

```aria
nan: f64 = 0.0 / 0.0;

// NaN propagates
Result: f64 = nan + 5.0;  // Still NaN
Result: f64 = nan * 10.0;  // Still NaN

// Check for NaN
when result.is_nan() then
    handle_error();
end
```

### Infinity

```aria
inf: f64 = 1.0 / 0.0;

// Infinity arithmetic
Result: f64 = inf + 100.0;  // Still +∞
Result: f64 = inf * 2.0;    // Still +∞
Result: f64 = inf / inf;    // NaN!
```

