rounded: i32 = (pi + 0.5) as i32;  // 3
```

---

## Common Patterns

### Safe Division

```aria
fn safe_divide(a: f64, b: f64) -> Result<f64> {
    when b == 0.0 then
        fail("Division by zero");
    end

    Result: f64 = a / b;

    when result.is_nan() or result.is_infinite() then
        fail("Invalid result");
    end

    pass(result);
}
```

### Numerical Integration

```aria
// Trapezoidal rule
fn integrate(f: fn(f64) -> f64, a: f64, b: f64, n: i32) -> f64 {
    h: f64 = (b - a) / (n as f64);
    sum: f64 = (f(a) + f(b)) / 2.0;

    till(n - 1, 1) {
        i: i32 = $ + 1;
        x: f64 = a + (i as f64) * h;
        sum += f(x);
    }

    return sum * h;
}
```

