## Common Generic Struct Patterns

### Option Type

```aria
enum Option<T> {
    Some(T),
    None
}

impl<T> Option<T> {
    fn is_some() -> bool {
        return match self {
            Some(_) => true,
            None => false
        };
    }

    fn unwrap() -> T {
        return match self {
            Some(value) => value,
            None => panic("Called unwrap on None")
        };
    }

    fn unwrap_or(default: T) -> T {
        return match self {
            Some(value) => value,
            None => default
        };
    }
}
```

### Result Type

```aria
enum Result<T, E> {
    Ok(T),
    Err(E)
}

impl<T, E> Result<T, E> {
