## Associated Types in Generic Structs

```aria
trait Iterator {
    type Item;

    fn next() -> Option<Self::Item>;
}

struct VecIterator<T> {
    data: Vec<T>,
    index: usize
}

impl<T> Iterator for VecIterator<T> {
    type Item = T;

