// ============================================================================
// Path Operations
// ============================================================================

/**
 * Get absolute path
 * 
 * Example:
 *   string:abs = fs.absolute("./config.txt");
 *   println(abs);  // /home/user/project/config.txt
 * 
 * @param path Relative or absolute path
 * @return Absolute path
 */
pub func:absolute = string(string:path) {
    wild int8*:c_path = path.data;

    string:result = aria_path_absolute_string(c_path);

    return result;
};

/**
 * Get directory name from path
 * 
 * Example:
 *   string:dir = fs.dirname("/home/user/file.txt");
 *   println(dir);  // /home/user
