// ============================================================================
// Glob Pattern Matching - FFI Bridge to aglob (GlobEngine)
// ============================================================================
// Provides deterministic file pattern matching for build systems.
// Patterns use ABC glob syntax: *, **, ?, [abc], [!abc]
//
// Reference: docs/gemini/responses/remaining/GlobEngine FFI Bridge Design.txt

// External Declarations - C FFI Bindings to aglob library
extern "C" {
    // GlobResult struct (matches C layout exactly)
    // Memory layout: char** paths, size_t count, int error_code

    // Match single glob pattern
    // @param base_dir Root directory for matching (null-terminated C string)
    // @param pattern  Glob pattern to match (null-terminated C string)
    // @return GlobResult with paths array and count
    // MEMORY: Caller must call aria_glob_free() to release memory
    func:aria_glob_match = GlobResult(wild int8*:base_dir, wild int8*:pattern);

    // Match with custom options
    func:aria_glob_match_with_options = GlobResult(
        wild int8*:base_dir,
        wild int8*:pattern,
        wild GlobOptions*:options
    );

    // Match multiple patterns (logical OR, deduplicated)
    func:aria_glob_match_all = GlobResult(
        wild int8*:base_dir,
        wild int8**:patterns,
        int64:pattern_count
    );

    // Free memory allocated by aria_glob_match functions
    // MUST be called to prevent memory leaks
    func:aria_glob_free = void(wild GlobResult*:result);

    // Get human-readable error string
    func:aria_glob_error_string = wild int8*(int32:error_code);

    // Validate pattern syntax (1 = valid, 0 = invalid)
    func:aria_glob_validate_pattern = int32(wild int8*:pattern);

    // Check if path matches pattern (without traversal)
    func:aria_glob_path_matches = int32(
        wild int8*:path,
        wild int8*:pattern,
        int32:case_sensitive
    );
}

// GlobResult struct - matches C layout for FFI
// Memory is allocated by C++ and must be freed via aria_glob_free()
pub struct GlobResult {
    wild int8**:paths;   // Array of null-terminated path strings (wild memory)
    int64:count;         // Number of paths in array
    int32:error_code;    // 0 = OK, >0 = error (see GlobError enum)
}

// GlobOptions struct - matches C layout for FFI
pub struct GlobOptions {
    int32:case_sensitive;        // 1 = case sensitive, 0 = case insensitive
    int32:follow_symlinks;       // 1 = follow symlinks, 0 = don't follow
    int64:max_depth;             // 0 = unlimited, >0 = limit
    int32:files_only;            // 1 = only files, 0 = include directories
    int32:directories_only;      // 1 = only directories, 0 = include files
    int32:include_hidden;        // 1 = include dotfiles, 0 = skip
    int32:skip_permission_errors; // 1 = skip, 0 = fail on permission denied
}

// GlobError enum - maps to C++ GlobError
pub enum GlobError {
    OK = 0,
    INVALID_BASE_DIR = 1,
    PATTERN_SYNTAX_ERROR = 2,
    ACCESS_DENIED = 3,
    FILESYSTEM_ERROR = 4,
    SYMLINK_CYCLE = 5,
    MAX_DEPTH_EXCEEDED = 6,
    UNKNOWN_ERROR = 99
}

// ============================================================================
// High-Level Safe Wrapper API
// ============================================================================
// These functions handle memory management automatically, converting
// between wild C pointers and managed Aria strings.

/**
 * Expand a glob pattern and return matching file paths.
 *
 * This is the primary entry point for glob matching. Results are
 * deterministically sorted for reproducible builds.
 *
 * Example:
 *   result<array<string>>:files = fs.glob("src/**/*.aria", ".");
 *   if (files.is_ok()) {
 *       array<string>:paths = files.unwrap();
 *       for (path in paths) {
 *           println(path);
 *       }
 *   }
 *
 * @param pattern Glob pattern (*, **, ?, [abc])
 * @param base_dir Base directory for matching (default: ".")
 * @return Array of matching paths, or error
 */
pub func:glob = result<array<string>>(string:pattern, string:base_dir) {
    // Convert Aria strings to C strings
    wild int8*:c_pattern = pattern.data;
    wild int8*:c_base = base_dir.data;

    // Call FFI function
    GlobResult:res = aria_glob_match(c_base, c_pattern);

    // Ensure cleanup of FFI result (even on error path)
    defer aria_glob_free(@res);

    // Check for errors
    if (res.error_code != 0) {
        fail(ERR);
    }

    // Convert to managed Aria array
    array<string>:matches = array_new<string>(res.count);

    // Copy each path from wild memory to managed memory
    int64:i = 0i64;
    while (i < res.count) {
        wild int8*:path_cstr = res.paths[i];
        string:path = string_from_cstr(path_cstr);
        array_push(@matches, path);
        i = i + 1;
    }

    pass(matches);
};

/**
 * Expand a glob pattern with default base directory.
 * Convenience wrapper that uses current directory as base.
 *
 * Example:
 *   result<array<string>>:files = fs.glob_here("*.aria");
 */
pub func:glob_here = result<array<string>>(string:pattern) {
    pass(glob(pattern, "."));
};

/**
 * Expand multiple glob patterns (logical OR).
 * Results are combined, sorted, and deduplicated.
 *
 * Example:
 *   array<string>:patterns = ["src/**/*.aria", "tests/**/*.aria"];
 *   result<array<string>>:files = fs.glob_all(patterns, ".");
 */
pub func:glob_all = result<array<string>>(array<string>:patterns, string:base_dir) {
    wild int8*:c_base = base_dir.data;

    // Convert pattern array to C array
    int64:count = patterns.length();
    wild int8**:c_patterns = alloc<int8*>(count);
    if (c_patterns == NULL) {
        fail(ERR);
    }
    defer free<int8*>(c_patterns);

    // Copy pattern pointers
    int64:i = 0i64;
    while (i < count) {
        c_patterns[i] = patterns[i].data;
        i = i + 1;
    }

    // Call FFI
    GlobResult:res = aria_glob_match_all(c_base, c_patterns, count);
    defer aria_glob_free(@res);

    if (res.error_code != 0) {
        fail(ERR);
    }

    // Convert to managed array
    array<string>:matches = array_new<string>(res.count);

    i = 0;
    while (i < res.count) {
        wild int8*:path_cstr = res.paths[i];
        string:path = string_from_cstr(path_cstr);
        array_push(@matches, path);
        i = i + 1;
    }

    pass(matches);
};

/**
 * Check if a path matches a glob pattern (without directory traversal).
 *
 * Example:
 *   if (fs.matches("src/main.aria", "**/*.aria")) {
 *       println("Match!");
 *   }
 */
pub func:matches = bool(string:path, string:pattern) {
    wild int8*:c_path = path.data;
    wild int8*:c_pattern = pattern.data;

    int32:result = aria_glob_path_matches(c_path, c_pattern, 1);

    return result == 1;
};

/**
 * Validate a glob pattern syntax.
 *
 * Example:
 *   if (!fs.glob_valid("[unclosed")) {
 *       eprintln("Invalid pattern!");
 *   }
 */
pub func:glob_valid = bool(string:pattern) {
    wild int8*:c_pattern = pattern.data;

    int32:result = aria_glob_validate_pattern(c_pattern);

    return result == 1;
};

