## Best Practices

### ✅ DO: Wrap Unsafe Extern Calls

```aria
extern "C" {
    fn unsafe_c_function(ptr: *void) -> i32;
}

// Safe wrapper
pub fn safe_function(data: *Data) -> Result<i32> {
    if data == NULL {
        return Err("Null pointer");
    }

    Result: i32 = extern.unsafe_c_function(data);
    if result < 0 {
        return Err("C function failed");
    }

    return Ok(result);
}
