/// Count number of set bits (population count)

Implementation:
```aria
func:popcount_i32 = int32(int32:n) {
int32:count = 0i32;
    int32:val = n;

    // Handle negative numbers
    bool:negative = (val < 0);
    if (negative) {
        val = (0 - val);
    } else {}

    while (val != 0) {
        int32:bit = (val - ((val / 2) * 2));  // Manual modulo 2
        bool:is_one = (bit == 1);
        if (is_one) {
            count = (count + 1);
        } else {}
        val = (val / 2);
    }

    pass(count);
};
}
```

