func:is_power_of_two = bool(uint32:n) {
bool:result = false;
    uint32:zero = 0i32;
    bool:positive = (n > zero);

    if (positive) {
        uint32:one = 1i32;
        uint32:n_minus_1 = (n - one);
        uint32:test = (n & n_minus_1);
        bool:is_zero = (test == zero);
        if (is_zero) {
            result = true;
        } else {
            result = false;
        }
    } else {
        result = false;
    }

    pass(result);
};
}
