## Example: Maximum-Security Key Verification

```aria
// Verify RSA-16384 key parameters
// (Simplified - full RSA-16384 needs bigger representation)

int4096:p = load_prime("rsa16384_p.bin");
int4096:q = load_prime("rsa16384_q.bin");

if (p == ERR || q == ERR) {
    stderr.write("Prime load failed\n");
    !!! ERR_CRYPTO_PRIME_LOAD;
}

// Verify primes are odd
int4096:one = 1i4096;
int4096:p_odd = p & one;
int4096:q_odd = q & one;

if (p_odd != one || q_odd != one) {
    stderr.write("Primes must be odd (except 2, which is too small)\n");
    !!! ERR_CRYPTO_PRIME_EVEN;
}

// Verify e and phi(n) coprime
int4096:e = 65537i4096;  // Standard public exponent
int4096:p_minus_1 = p - one;
int4096:q_minus_1 = q - one;

// Simplified phi check (real version needs full 8192-bit phi)
(int4096:gcd_p, _, _) = extended_gcd_4096(e, p_minus_1);
(int4096:gcd_q, _, _) = extended_gcd_4096(e, q_minus_1);

if (gcd_p != one || gcd_q != one) {
    stderr.write("Public exponent not coprime with p-1 or q-1\n");
    !!! ERR_CRYPTO_EXPONENT_NOT_COPRIME;
}

stderr.write("✅ RSA-16384 key parameters validated\n");
```

