### Generic Function with Multiple Constraints

```aria
fn unique_sorted<T>(array: []T) -> []T
    where T: Comparable,
          T: Hashable,
          T: Clone {

    seen: Set<T> = Set::new();
    unique: []T = [];

    till(array.length - 1, 1) {
        item: T = array[$];
        when !seen.contains(item.clone()) then
            seen.insert(item.clone());
            unique.push(item);
        end
    }

    return sort(unique);
}

// Usage
