int2048:max = MAX_INT2048;
int2048:overflow = max + max;  // Returns ERR sentinel

if (overflow == ERR) {
    stderr.write("Overflow in cryptographic computation!\n");
    !!! ERR_CRYPTO_OVERFLOW;
}
```

