Parse a JSON number

Implementation:
```aria
func:parse_number = flt64(Tokenizer@:tok) {
wild int8->:buffer = alloc_array<int8>(64i64);
    int32:len = 0i32;

    // Handle negative sign
    int8:ch = peek(tok) ? 0i8;
    if (ch == 45i8) {  // '-'
        buffer[len] = ch;
        len = len + 1;
        advance(tok) ? 0i8;
    } else {
        // no sign
    }

    // Parse digits before decimal
    loop {
        ch = peek(tok) ? 0i8;
        if (is_digit(ch) ? 0i8) {
            buffer[len] = ch;
            len = len + 1;
            advance(tok) ? 0i8;
        } else {
            break;
        }
    }

    // Parse decimal part if present
    ch = peek(tok) ? 0i8;
    if (ch == 46i8) {  // '.'
        buffer[len] = ch;
        len = len + 1;
        advance(tok) ? 0i8;

        // Parse digits after decimal
        loop {
            ch = peek(tok) ? 0i8;
            if (is_digit(ch) ? 0i8) {
                buffer[len] = ch;
                len = len + 1;
                advance(tok) ? 0i8;
            } else {
                break;
            }
        }
    } else {
        // no decimal
    }

    // Null terminate and parse
    buffer[len] = 0i8;

    // Use stdlib parse_float
    extern "aria" {
        func:parse_float_c = flt64(int8->:str);
    }

    flt64:result = parse_float_c(buffer);
    free<int8>(buffer);

    return result;
};
}
```

