### Type Conversions

```aria
// Widening conversions (always safe)
let small: uint64 = 12345;
let large: uint4096 = uint4096(small);  // Zero-extended

let medium: uint256 = 0xABCDEF;
let larger: uint2048 = uint2048(medium);  // Zero-extended

