### Worker Pool

```aria
import std.sync.{Channel, Thread};

struct WorkerPool {
    workers: []Thread,
    sender: Channel<Task>,
}

impl WorkerPool {
    pub fn new(size: i32) -> WorkerPool {
        channel: Channel<Task> = Channel.new();
        workers: []Thread = [];

        till(size - 1, 1) {
            worker: Thread = Thread.spawn(worker_thread, channel.clone());
            workers.push(worker);
        }

        return WorkerPool {
            workers: workers,
            sender: channel,
        };
    }

    pub fn execute(task: Task) {
        self.sender.send(task);
    }
}
