/// Comparison and Ordering Utilities

/// Compare two int32 values (-1 if a < b, 0 if equal, 1 if a > b)
pub func:compare_i32 = int32(int32:a, int32:b) {
    int32:result = 0i32;
    bool:less = (a < b);
    bool:greater = (a > b);

    if (less) {
        int32:zero = 0i32;
        int32:one = 1i32;
        result = zero - one;
    } else {
        if (greater) {
            int32:one_val = 1i32;
            result = one_val;
        } else {
            int32:zero_val = 0i32;
            result = zero_val;
        }
    }
    pass(result);
};

