// 1T = 1×3¹ + (-1)×3⁰ = 3 - 1 = 2
// 111 = 1×9 + 1×3 + 1×1 = 13

bt_minus_two: tryte = parse_bt("T1");  // -2
bt_two: tryte = parse_bt("1T");        // +2
bt_thirteen: tryte = parse_bt("111");  // 13
```

