// Spawn Functions (research_029 Section 6.3)
// =============================================================================

/// Spawn an async task
/// @param future The future to execute
/// @return Handle to the spawned task
pub func:spawn<T> = TaskHandle<T>(Future<T>:future) {
    if (SCHEDULER == NULL) {
        // Auto-initialize scheduler
        scheduler_init(0);
    }

    // Allocate coroutine frame
    wild CoroutineFrame@:frame = alloc<CoroutineFrame>(1);
    frame->state = CoroState.SUSPENDED;
    frame->waiting_on = NULL;
    frame->has_wild_affinity = false;
    frame->affinity_thread_id = -1;

    // Create task
    Task@:task = alloc<Task>(1);
    task->frame = frame;
    task->task_id = atomic_fetch_add(@SCHEDULER->next_task_id, 1);
    task->priority = PRIORITY_NORMAL;
    task->has_wild_affinity = false;
    task->affinity_thread_id = -1;

    // Push to global queue
    deque_push(@SCHEDULER->global_queue, task);

    // Return handle for await
    TaskHandle<T>:handle = {
        task_id: task->task_id,
        task: task
    };
    pass(handle);
};

/// Spawn a blocking task on a dedicated thread pool
/// Use this for CPU-bound work or legacy synchronous code
pub func:spawn_blocking<T> = TaskHandle<T>(func:action = T()) {
    // spawn_blocking uses a separate thread pool that doesn't block
    // the async executor

    // For now, just execute synchronously (placeholder)
    // Full implementation would use a dedicated blocking thread pool
    T:result = action();

    TaskHandle<T>:handle = {
        task_id: -1,
        task: NULL,
        result: result,
        completed: true
    };
    pass(handle);
};

/// Spawn a task with Wild Affinity (captures wild pointers)
/// This task will be pinned to the current worker thread
pub func:spawn_local<T> = TaskHandle<T>(Future<T>:future) {
    TaskHandle<T>:handle = spawn(future);

    // Mark as wild affinity
    if (handle.task != NULL) {
        handle.task->has_wild_affinity = true;
        // Will be set when first polled on a worker
    }

    pass(handle);
};

// =============================================================================
// Task Handle (for await)
// =============================================================================

/// Handle to a spawned task
pub struct TaskHandle<T> {
    int32:task_id;
    wild Task@:task;
    T:result;
    bool:completed;
}

/// Await a task handle (get the result when ready)
pub func:await_task<T> = T(TaskHandle<T>:handle) {
    if (handle.completed) {
        pass(handle.result);
    }

    // Poll until complete
    // This is called from within an async context
    while (handle.task != NULL && handle.task->frame->state != CoroState.COMPLETE) {
        @yield_current();  // Suspend current coroutine
    }

    pass(handle.result);
};

// =============================================================================
// Combinators (research_029 Section 4.3)
// =============================================================================

/// Join two futures - wait for both to complete
pub func:join<A, B> = result<(A, B)>(Future<A>:f1, Future<B>:f2) {
    // Poll both futures until both are ready
    bool:f1_done = false;
    bool:f2_done = false;
    A:result1;
    B:result2;

    while (!f1_done || !f2_done) {
        if (!f1_done) {
            Context:ctx1 = @current_context();
            Poll<A>:p1 = f1.poll(@ctx1);
            if (p1.state == PollState.READY) {
                f1_done = true;
                result1 = p1.value;
            } else if (p1.state == PollState.ERROR) {
                fail(ERR);
            }
        }

        if (!f2_done) {
            Context:ctx2 = @current_context();
            Poll<B>:p2 = f2.poll(@ctx2);
            if (p2.state == PollState.READY) {
                f2_done = true;
                result2 = p2.value;
            } else if (p2.state == PollState.ERROR) {
                fail(ERR);
            }
        }

        if (!f1_done || !f2_done) {
            @yield_current();
        }
    }

    (A, B):tuple = (result1, result2);
    pass(tuple);
};

/// Select - race two futures, return the first to complete
/// The losing future is cancelled (dropped)
pub func:select<T> = result<T>(Future<T>:f1, Future<T>:f2) {
    while (true) {
        Context:ctx1 = @current_context();
        Poll<T>:p1 = f1.poll(@ctx1);
        if (p1.state == PollState.READY) {
            // f1 won - cancel f2 by dropping
            @drop(f2);
            pass(p1.value);
        } else if (p1.state == PollState.ERROR) {
            @drop(f2);
            fail(ERR);
        }

        Context:ctx2 = @current_context();
        Poll<T>:p2 = f2.poll(@ctx2);
        if (p2.state == PollState.READY) {
            // f2 won - cancel f1 by dropping
            @drop(f1);
            pass(p2.value);
        } else if (p2.state == PollState.ERROR) {
            @drop(f1);
            fail(ERR);
        }

        // Both pending - yield
        @yield_current();
    }
};

