/// Timer future - completes after specified milliseconds
pub struct Timer {
    int64:deadline_ms;   // Absolute deadline (monotonic time)
    bool:expired;
}

/// Create a timer that fires after the specified duration
pub func:timeout = Timer(int64:duration_ms) {
    int64:now = @monotonic_time_ms();
    Timer:t = {
        deadline_ms: now + duration_ms,
        expired: false
    };
    pass(t);
};

/// Create a timer that fires at a specific instant
pub func:deadline = Timer(int64:deadline_ms) {
    Timer:t = {
        deadline_ms: deadline_ms,
        expired: false
    };
    pass(t);
};

/// Timer implements Future<void>
impl Future<void> for Timer {
    func:poll = Poll<void>(Context@:ctx) {
        int64:now = @monotonic_time_ms();
        if (now >= self.deadline_ms) {
            self.expired = true;
            pass(poll_ready<void>(NIL));
        }

        // Register waker with timer wheel (reactor)
        // For now, just return pending
        pass(poll_pending<void>());
    };
}

