// TBB Error Propagation (research_029 Section 4.2, 9.3)
// =============================================================================
// TBB sticky errors propagate across await points without exceptions

/// Check if a TBB result is an error and convert to Poll error
pub func:check_tbb<T> = Poll<T>(tbb64:value, T:result) {
    if (value == math.TBB64_ERR) {
        pass(poll_error<T>(-128));  // TBB error code
    }
    pass(poll_ready<T>(result));
};

/// TBB-aware future that propagates sticky errors
pub struct TbbFuture<T> {
    Future<tbb64>:inner;
}

impl Future<tbb64> for TbbFuture<tbb64> {
    func:poll = Poll<tbb64>(Context@:ctx) {
        Poll<tbb64>:p = self.inner.poll(ctx);

        if (p.state == PollState.READY) {
            // Check for TBB error sentinel
            if (p.value == math.TBB64_ERR) {
                pass(poll_error<tbb64>(-128));
            }
        }

        pass(p);
    };
}

