    cache: wild aria_slab_cache@,
    total_slabs: uint64@,
    total_objects: uint64@,
    allocated_objects: uint64@,
    free_objects: uint64@,
    total_capacity: uint64@
);
extern fn aria_slab_cache_object_size(cache: wild aria_slab_cache@) -> uint64;
extern fn aria_slab_cache_slab_size(cache: wild aria_slab_cache@) -> uint64;

// Opaque C++ types
struct aria_slab_cache;
struct AriaSlabResult;
struct aria_slab_ctor;
struct aria_slab_dtor;

