/// Print a signed 32-bit integer to stdout
pub func:print_int32 = NIL(int32:n) {
    // Handle negative numbers
    if (n < 0i32) {
        print_char(45i32) ? NIL;  // '-'
        n = 0i32 - n;  // Make positive
    }

    // Handle zero specially
    if (n == 0i32) {
        print_digit(0i32) ? NIL;
    } else {
        // Extract digits
        int32[10]:digits;
        int32:count = 0i32;

        while (n > 0i32) {
            int32:digit = n % 10i32;
            digits[count] = digit;
            count = count + 1i32;
            n = n / 10i32;
        }

        // Print in reverse order
        int32:i = count - 1i32;
        while (i >= 0i32) {
            print_digit(digits[i]) ? NIL;
            i = i - 1i32;
        }
    }
    pass(NIL);
};

/// Print a signed 64-bit integer to stdout
pub func:print_int64 = NIL(int64:n) {
    // Handle negative numbers
    if (n < 0i64) {
        print_char(45i32) ? NIL;  // '-'
        n = 0i64 - n;  // Make positive
    }

    // Handle zero specially
    if (n == 0i64) {
        print_digit(0i32) ? NIL;
    } else {
        // Extract digits
        int32[20]:digits;
        int32:count = 0i32;

        while (n > 0i64) {
            int64:digit_64 = n % 10i64;
            // Narrow to int32 (safe for 0-9)
            int32:digit = 0i32;
            if (digit_64 == 0i64) digit = 0i32;
            else if (digit_64 == 1i64) digit = 1i32;
            else if (digit_64 == 2i64) digit = 2i32;
            else if (digit_64 == 3i64) digit = 3i32;
            else if (digit_64 == 4i64) digit = 4i32;
            else if (digit_64 == 5i64) digit = 5i32;
            else if (digit_64 == 6i64) digit = 6i32;
            else if (digit_64 == 7i64) digit = 7i32;
            else if (digit_64 == 8i64) digit = 8i32;
            else digit = 9i32;

            digits[count] = digit;
            count = count + 1i32;
            n = n / 10i64;
        }

        // Print in reverse order
        int32:i = count - 1i32;
        while (i >= 0i32) {
            print_digit(digits[i]) ? NIL;
            i = i - 1i32;
        }
    }
    pass(NIL);
};

