/// Simple Hash Functions

/// Simple integer hash (multiplicative hash)
func:hash_int32 = int32(int32:value) {
    int32:h = value;
    int32:mult = 2654435761;  // Golden ratio related
    int32:result = (h * mult);
    pass(result);
};

/// Combine two hash values
func:hash_combine = int32(int32:h1, int32:h2) {
    int32:shift1 = (h1 << 5);
    int32:shift2 = (h1 >> 27);
    int32:rotated = (shift1 | shift2);
    int32:result = (rotated ^ h2);
    pass(result);
