        rx = channel.receiver();
        consumer: Thread = Thread.spawn(|| consumer($, rx));
        consumers.push(consumer);
    }

    p.join();
    channel.close();

    till(consumers.length - 1, 1) {
        consumers[$].join();
    }
}
