func:pad_left_spaces = NIL(int8->:dest, int8->:src, int32:target_len) {
if (dest == NULL || src == NULL || target_len <= 0) {
        pass(NIL);
    }

    // Get source length
    int32:src_len = 0i32;
    while (src[src_len] != 0) {
        src_len = src_len + 1;
    }

    if (src_len >= target_len) {
        // Copy as-is if already long enough
        int32:i = 0i32;
        while (src[i] != 0) {
            dest[i] = src[i];
            i = i + 1;
        }
        dest[i] = 0;
        pass(NIL);
    } else {
        // Pad with spaces
    }

    int32:padding = target_len - src_len;
    int32:i = 0i32;

    // Write padding
    while (i < padding) {
        dest[i] = 32;
        i = i + 1;
    }

    // Copy source
    int32:j = 0i32;
    while (src[j] != 0) {
        dest[i] = src[j];
        i = i + 1;
        j = j + 1;
    }

    dest[i] = 0;
    pass(NIL);
};
}
```

