extern "C" {
    fn register_callback(cb: extern "C" fn(i32) -> i32);
}

// Define callback in Aria
#[no_mangle]
extern "C" fn my_callback(value: i32) -> i32 {
    return value * 2;
}

// Register it
extern.register_callback(my_callback);
```

