    // Try primary source
    Result<Data, string>:primary = fetch_from_primary(url);
    if primary.err == NULL then
        pass(primary.val);
    end

    stdout.write("Primary failed: {}, trying backup...\n", primary.err);

    // Try backup source
    Result<Data, string>:backup = fetch_from_backup(url);
    if backup.err == NULL then
