    till count loop
        complex<fix256>:sum = {real: fix256(0), imag: fix256(0)};
        int64:k = $;  // Iteration variable

        till count loop
            int64:n = $;
            fix256:angle = fix256(-2) * PI * fix256(k) * fix256(n) / fix256(count);

