func:partition_f64 = int32(*flt64:arr, int32:low, int32:high) {
flt64:pivot = arr[high];
    int32:i = low - 1;

    int32:j = low;
    till(high, 1i64) {
        if (arr[j] < pivot) {
            i = i + 1;
            flt64:temp = arr[i];
            arr[i] = arr[j];
            arr[j] = temp;
        }
        j = j + 1;
    }

    flt64:temp = arr[i + 1];
    arr[i + 1] = arr[high];
    arr[high] = temp;

    return i + 1;
};
