vec2:mouse_pos = vec2(640.0, 360.0);  // Center of 1280×720 screen

// Texture coordinates (UV mapping)
vec2:tex_coord = vec2(0.5, 0.5);  // Center of texture (range 0.0-1.0)

// Sprite position
