## Handling Comments

```aria
impl Lexer {
    fn skip_whitespace() {
        while true {
            c: char = self.peek();

            match c {
                ' ' | '\t' | '\r' => self.advance(),
                '\n' => {
                    self.line += 1;
                    self.column = 1;
                    self.advance();
                }
                '/' => {
                    if self.peek_next() == '/' {
                        // Line comment
                        while !self.is_at_end() && self.peek() != '\n' {
                            self.advance();
                        }
                    } else if self.peek_next() == '*' {
                        // Block comment
                        self.skip_block_comment();
                    } else {
                        return;
                    }
                }
                _ => return,
            }
        }
    }

    fn skip_block_comment() {
        self.advance();  // Skip /
        self.advance();  // Skip *

        depth: i32 = 1;

        while !self.is_at_end() && depth > 0 {
            if self.peek() == '/' && self.peek_next() == '*' {
                depth += 1;  // Nested comment
                self.advance();
                self.advance();
            } else if self.peek() == '*' && self.peek_next() == '/' {
                depth -= 1;
                self.advance();
                self.advance();
            } else {
                self.advance();
            }
        }
    }
}
```

