Binary search in sorted array (returns index or -1)

Implementation:
```aria
func:binary_search_i32 = int32(int32->:arr, int32:length, int32:target) {
int32:left = 0i32;
    int32:right = (length - 1);
    int32:result = -1;
    int32:cont = 1i32;

    while (cont) {
        bool:left_gt = (left > right);

        if (left_gt) {
            cont = 0;
        } else {
            int32:sum = (left + right);
            int32:mid = (sum / 2);
            int32:mid_val = arr[mid];

            bool:is_equal = (mid_val == target);
            if (is_equal) {
                result = mid;
                cont = 0;
            } else {
                bool:is_less = (mid_val < target);
                if (is_less) {
                    left = (mid + 1);
                } else {
                    right = (mid - 1);
                }
            }
        }
    }

    pass(result);
};
}
