    // Get basename first
    int32:sep = find_last_separator(path);
    int32:start = sep + 1;

    // Find extension
    int32:dot = find_extension_pos(path);
    int32:end_pos = (0 - 1);

    if (dot != (0 - 1)) {
        end_pos = dot;
    } else {
        // No extension, copy to end
        int32:i = 0i32;
        while (path[start + i] != 0) {
            dest[i] = path[start + i];
            i = i + 1;
        }
        dest[i] = 0;
        pass(NIL);
    }

    // Copy from start to dot
    int32:i = 0i32;
    while (start + i < end_pos) {
        dest[i] = path[start + i];
        i = i + 1;
    }

    dest[i] = 0;
    pass(NIL);
};
}
