fn main() {
    stddbg << "Starting ETL pipeline";

    // Read from stddati
    input_data: []Record = stddati.read_json()?;

    // Transform
    output_data: []Record = [];
    till(input_data.length - 1, 1) {
        transformed: Record = transform(input_data[$]);
        output_data.push(transformed);

