            // Narrow to int32 (safe for 0-9)
            int32:digit = 0i32;
            if (digit_64 == 0i64) digit = 0i32;
            else if (digit_64 == 1i64) digit = 1i32;
            else if (digit_64 == 2i64) digit = 2i32;
