if (key_pressed('W')) { move_input.z -= 1.0; }  // Forward
if (key_pressed('S')) { move_input.z += 1.0; }  // Backward
if (key_pressed('A')) { move_input.x -= 1.0; }  // Left
if (key_pressed('D')) { move_input.x += 1.0; }  // Right

