// Projectile motion
vec3:position = vec3(0.0, 0.0, 0.0);
vec3:initial_velocity = vec3(10.0, 20.0, 0.0);  // Launch angle
const vec3:gravity = vec3(0.0, -9.8, 0.0);  // m/s²
float:time = 0.0;
const float:dt = 0.016;

