    wei_per_eth: i256 = 1000000000000000000i256;
    return (eth as i256) * wei_per_eth;
}

// Convert wei to ETH
fn wei_to_eth(wei: i256) -> flt64 {
    wei_per_eth: i256 = 1000000000000000000i256;
    return (wei as flt64) / (wei_per_eth as flt64);
}
