### Modular Arithmetic

```aria
// Cryptographic modular exponentiation
fn mod_pow(base: i256, exp: i256, modulus: i256) -> i256 {
    Result: i256 = 1i256;
    base = base % modulus;

    while exp > 0i256 {
        when (exp % 2i256) == 1i256 then
            result = (result * base) % modulus;
        end
        exp = exp >> 1;
        base = (base * base) % modulus;
    }

    return result;
}
```

