```aria
tbb32:sensor_reading = read_temperature_sensor();

if (sensor_reading != ERR) {
    // Have valid reading, process it
    log.write("Temperature: ");
    sensor_reading.write_to(log);
    log.write("°C\n");
} else {
    stderr.write("Sensor malfunction\n");
}
```

