```aria
func:binomial_i32 = int32(int32:n, int32:k) {
int32:zero = 0i32;
    int32:one = 1i32;

    if (k < zero || k > n) {
        return zero;
    } else {}

    if (k == zero || k == n) {
        return one;
    } else {}

    // Optimize by using smaller k
    if (k > (n - k)) {
        k = n - k;
    } else {}

    int32:result = one;
    int32:i = zero;

    while (i < k) {
        result = result * (n - i);
        result = result / (i + one);
        i = i + one;
    }

    return result;
};
}
