// Merge helper for merge sort
pub func:merge_i32 = NIL(int32->:arr, int32:left, int32:mid, int32:right, int32->:temp) {
    int32:i = left;
    int32:j = mid + 1;
    int32:k = left;

    // Merge the two halves into temp array
    while (i <= mid && j <= right) {
        if (arr[i] <= arr[j]) {
            temp[k] = arr[i];
            i = i + 1;
        } else {
            temp[k] = arr[j];
            j = j + 1;
