## Type Parameter Scope

```aria
struct Box<T> {
    value: T
    // T in scope for struct
}

impl<T> Box<T> {
    // T from struct is in scope

    fn get() -> T {
        return self.value;
    }

    // U is NEW parameter, separate from T
    fn map<U>(f: fn(T) -> U) -> Box<U> {
        return Box{value: f(self.value)};
    }
}
```

