## Real-World Examples

### Retry Logic

```aria
fn retry<T>(f: fn() -> T?, max_attempts: i32) -> T? {
    attempts: i32 = 0;

    while attempts < max_attempts {
        Result: T? = f();
        when result != ERR then
            return result;
        end

        attempts = attempts + 1;
        stddbg << "Retry " << attempts << "/" << max_attempts << "\n";
    }

    return ERR;
}

// Usage
data: string? = retry(|| fetch_from_api(), 3);
```

### Pipeline Processing

```aria
fn pipeline<T>(value: T, steps: []fn(T) -> T) -> T {
    Result: T = value;
    till(steps.length - 1, 1) {
        step: fn(T) -> T = steps[$];
        result = step(result);
    }
    return result;
}

// Data transformation pipeline
text: string = "  Hello World  ";
processed: string = pipeline(text, [
    |s| s.trim(),
    |s| s.lowercase(),
    |s| s.replace(" ", "_")
]);
// "hello_world"
```

