```aria
fn validate<T>(value: T, validators: []fn(T) -> bool) -> bool {
    till(validators.length - 1, 1) {
        validator: fn(T) -> bool = validators[$];
        when !validator(value) then
            return false;
        end
    }
    return true;
}

