```aria
struct EventDispatcher<T> {
    handlers: []fn(T)
}

impl<T> EventDispatcher<T> {
    fn new() -> EventDispatcher<T> {
        return EventDispatcher{handlers: []};
    }

    fn on(handler: fn(T)) {
        self.handlers.push(handler);
    }

    fn emit(event: T) {
        till(self.handlers.length - 1, 1) {
            handler: fn(T) = self.handlers[$];
            handler(event);
        }
    }
}

