Conversion Utilities for Number Formatting

use std.io.*;

/// Extract digit at specific position (0 = ones, 1 = tens, etc.)

Implementation:
```aria
func:digit_at = int32(int32:n, int32:pos) {
int32:val = n;
    int32:i = 0i32;

    // Handle negative
    bool:negative = (val < 0i32);
    if (negative) {
        val = (0i32 - val);
    } else {}

    // Divide by 10^pos
    while (i < pos) {
        val = (val / 10i32);
        i = (i + 1i32);
    }

    // Get last digit
    int32:digit = (val - ((val / 10i32) * 10i32));
    pass(digit);
};
}
```

