    end
}

when found then
    stdout << "Found it!";
end
```

---

## Truth Tables

### AND

| A | B | A and B |
|---|---|---------|
| false | false | false |
| false | true | false |
| true | false | false |
| true | true | true |

### OR

| A | B | A or B |
|---|---|--------|
| false | false | false |
| false | true | true |
| true | false | true |
| true | true | true |

### NOT

| A | !A |
|---|-----|
| false | true |
| true | false |

