## Real-World Examples

### Database Transaction

```aria
struct Transaction {
    conn: &Connection,
    active: bool
}

impl Transaction {
    fn begin(conn: &Connection) -> Transaction {
        conn.execute("BEGIN");
        return Transaction{conn: conn, active: true};
    }

    fn commit() {
        self.conn.execute("COMMIT");
        self.active = false;
    }
}

impl Drop for Transaction {
    fn drop() {
        when self.active then
            self.conn.execute("ROLLBACK");
        end
    }
}

