// Automatically normalized to {0, 2, 3} = 2/3

// GCD manually
tbb8:a = 12;
tbb8:b = 18;
tbb8:gcd = gcd8(a, b);  // 6

tbb8:reduced_num = a / gcd;  // 2
tbb8:reduced_denom = b / gcd;  // 3

