## Advanced Examples

### Example 1: Collatz Sequence

```aria
int64:n = 27;

while (n != 1) {
    print(`&{n}`);
    n = is (n % 2 == 0) : n / 2 : n * 3 + 1;
}

// Combined with loop:
loop(1, 100, 1) {
    int64:n = $;
    int64:steps = 0;

    while (n != 1) {
        n = is (n % 2 == 0) : n / 2 : n * 3 + 1;
        steps++;
    }

    print(`Collatz(&{$}) takes &{steps} steps`);
}
```

### Example 2: Matrix Multiplication

```aria
int64[10][10]:A;
int64[10][10]:B;
int64[10][10]:C;

loop(0, 9, 1) {
    int64:i = $;
    loop(0, 9, 1) {
        int64:j = $;
        int64:sum = 0;

        loop(0, 9, 1) {
            int64:k = $;
            sum += A[i][k] * B[k][j];
        }

        C[i][j] = sum;
    }
}
```

### Example 3: Prime Sieve

```aria
bool[1000]:isPrime;

// Initialize all as prime
loop(2, 999, 1) {
    isPrime[$] = true;
}

// Sieve
loop(2, 999, 1) {
    int64:p = $;
    if (isPrime[p]) {
        // Mark multiples as not prime
        loop(p * 2, 999, p) {
            isPrime[$] = false;
        }
    }
}

// Print primes
loop(2, 999, 1) {
    if (isPrime[$]) {
        print(`&{$}`);
    }
}
```

### Example 4: Histogram

```aria
int64[10]:histogram;  // Bins 0-9

// Count occurrences
loop(0, data.length - 1, 1) {
    int64:value = data[$];
    int64:bin = value / 10;  // Group into bins
    histogram[bin]++;
}

// Display
loop(0, 9, 1) {
    print(`Bin &{$}: &{histogram[$]}`);
}
```

