// Create timestamp from date components (simplified, no timezone)
// Year: full year (e.g., 2026), Month: 1-12, Day: 1-31
// Hour: 0-23, Minute: 0-59, Second: 0-59
pub func:make_timestamp = int64(int32:year, int32:month, int32:day, int32:hour, int32:minute, int32:second) {
    // Count days from epoch (1970-01-01)
    int64:total_days = 0i64;

    // Add days for complete years
    int32:y = 1970;
    while (y < year) {
        total_days = total_days + days_in_year(y);
        y = y + 1;
    }

    // Add days for complete months in current year
    int32:m = 1i32;
    while (m < month) {
        total_days = total_days + days_in_month(year, m);
        m = m + 1;
    }

    // Add remaining days
    total_days = total_days + (day - 1);

    // Convert to seconds
    int64:seconds = total_days * 86400;
    seconds = seconds + (hour * 3600);
    seconds = seconds + (minute * 60);
    seconds = seconds + second;

    return seconds;
};

